__global__ void
kmeans_swap(float  *feature,   
			float  *feature_swap,
			int     npoints,
			int     nfeatures
){

	unsigned int tid = blockIdx.x * blockDim.x + threadIdx.x;



    if (tid < npoints){
	    for(int i = 0; i <  nfeatures; i++)
		    feature_swap[i * npoints + tid] = feature[tid * nfeatures + i];
    }

}

