	err = cudaMalloc(&d_membership, n_points * sizeof(int));
	if(err != cudaSuccess) { printf("ERROR: cudaMalloc d_membership (size:%d) => %d\n", n_points, err); return -1;}
#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
    mem_alloc_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	cudaEvent_t event;
	cudaEventCreate(&event);

	err = cudaMemcpy(d_feature, feature[0], n_points * n_features * sizeof(float), cudaMemcpyHostToDevice);
	if(err != cudaSuccess) { printf("ERROR: cudaMemcpy d_feature (size:%d) => %d\n", n_points * n_features, err); return -1; }
#ifdef TIMING
    cudaEventRecord(event);
