int	kmeansOCL(float **feature,    
           int     n_features,
           int     n_points,
           int     n_clusters,
           int    *membership,
		   float **clusters,
		   int     *new_centers_len,
           float  **new_centers)	
{

	int delta = 0;
	int i, j, k;
	cudaError_t err = cudaSuccess;
	cudaEvent_t event;

	size_t global_work = n_points; 


	size_t local_work_size=BLOCK_SIZE2; 
	if(global_work%local_work_size !=0)
	  global_work=(global_work/local_work_size+1)*local_work_size;

	err = cudaMemcpy(d_cluster, clusters[0], n_clusters * n_features * sizeof(float), cudaMemcpyHostToDevice);
	if(err != cudaSuccess) { printf("ERROR: cudaMemcpy d_cluster (size:%d) => %d\n", n_points, err); return -1; }
#ifdef TIMING
    cudaEventCreate(&event);
    cudaEventRecord(event);
    cudaEventSynchronize(event);
    float milliseconds = 0;
    cudaEventElapsedTime(&milliseconds, event);
    h2d_time += milliseconds;
    cudaEventDestroy(event);
#endif

	int size = 0; int offset = 0;

	kmeans_kernel_c<<<global_work/local_work_size, local_work_size>>>(d_feature_swap, d_cluster, d_membership, n_points, n_clusters, n_features, offset, size);
	err = cudaDeviceSynchronize();
	if(err != cudaSuccess) { printf("ERROR: kmeans_kernel_c kernel failed\n"); return -1; }
#ifdef TIMING
    cudaEventCreate(&event);
    cudaEventRecord(event);
    cudaEventSynchronize(event);
    cudaEventElapsedTime(&milliseconds, event);
    kernel_time += milliseconds;
    cudaEventDestroy(event);
#endif

	err = cudaMemcpy(membership_OCL, d_membership, n_points * sizeof(int), cudaMemcpyDeviceToHost);
	if(err != cudaSuccess) { printf("ERROR: Memcopy Out\n"); return -1; }
#ifdef TIMING
    cudaEventCreate(&event);
    cudaEventRecord(event);
    cudaEventSynchronize(event);
    cudaEventElapsedTime(&milliseconds, event);
    d2h_time += milliseconds;
    cudaEventDestroy(event);
#endif

	delta = 0;
	for (i = 0; i < n_points; i++)
	{
		int cluster_id = membership_OCL[i];
		new_centers_len[cluster_id]++;
		if (membership_OCL[i] != membership[i])
		{
			delta++;
			membership[i] = membership_OCL[i];
		}
		for (j = 0; j < n_features; j++)
		{
			new_centers[cluster_id][j] += feature[i][j];
		}
	}

	return delta;
}

